import{_ as a,o as t,c as r,a0 as o}from"./chunks/framework.DgPozsi0.js";const u=JSON.parse('{"title":"[React官網] React 19.2 教程","description":"","frontmatter":{"title":"[React官網] React 19.2 教程"},"headers":[],"relativePath":"pages/f2e/docReact/reactDev/02/reactDev_02_01.md","filePath":"pages/f2e/docReact/reactDev/02/reactDev_02_01.md"}'),c={name:"pages/f2e/docReact/reactDev/02/reactDev_02_01.md"};function l(d,e,i,s,n,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="創建一個-react-應用" tabindex="-1">創建一個 React 應用 <a class="header-anchor" href="#創建一個-react-應用" aria-label="Permalink to &quot;創建一個 React 應用&quot;">​</a></h1><p>如果你想用 <code>React</code> 構建一個新的應用或網站，我們推薦從一個框架開始。</p><p>如果你的應用程序具有現有框架無法很好滿足的約束，你更喜歡構建自己的框架，或者你只想學習 <code>React</code> 應用程序基礎知識，你可以選擇 <a href="/vitepress-study/pages/f2e/docReact/reactDev/02/reactDev_02_02.html">從零構建一個 React 應用</a>。</p><h2 id="全端框架" tabindex="-1">全端框架 <a class="header-anchor" href="#全端框架" aria-label="Permalink to &quot;全端框架&quot;">​</a></h2><p>這些推薦的框架支持你在生產環境中部署和擴展應用所需的所有功能。它們集成了 <code>React</code> 的最新特性，並充分利用了 <code>React</code> 的架構。</p><ul><li><h4 id="全端框架不需要伺服器" tabindex="-1">全端框架不需要伺服器 <a class="header-anchor" href="#全端框架不需要伺服器" aria-label="Permalink to &quot;全端框架不需要伺服器&quot;">​</a></h4><p>本頁列出的所有框架都支持 <code>客戶端渲染（CSR）</code>、<code>單頁應用（SPA）</code>和<code>靜態站點生成（SSG）</code>。這些應用可以部署到 <code>CDN</code> 或<code>靜態託管服務（無需服務器）</code>。此外，這些框架允許你根據實際需求，針對特定路由單獨啟用服務端渲染。</p><p>這意味著你可以從純客戶端應用開始構建，後續需求變更時，無需重寫整個應用，即可在特定路由上啟用服務端功能。</p></li><li><h3 id="next-js-app-router" tabindex="-1">Next.js（App Router） <a class="header-anchor" href="#next-js-app-router" aria-label="Permalink to &quot;Next.js（App Router）&quot;">​</a></h3><ul><li><h4 id="定義" tabindex="-1">定義 <a class="header-anchor" href="#定義" aria-label="Permalink to &quot;定義&quot;">​</a></h4><p><a href="https://nextjs.org/docs" target="_blank" rel="noreferrer">Next.js 的 App Router</a> 是一個 <code>React</code> 框架，充分利用了 <code>React</code> 的架構，支持全端 <code>React</code> 應用。</p></li><li><h4 id="初始化命令" tabindex="-1">初始化命令 <a class="header-anchor" href="#初始化命令" aria-label="Permalink to &quot;初始化命令&quot;">​</a></h4><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-next-app@latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h4 id="維護與部署" tabindex="-1">維護與部署 <a class="header-anchor" href="#維護與部署" aria-label="Permalink to &quot;維護與部署&quot;">​</a></h4><p>由 <a href="https://vercel.com/" target="_blank" rel="noreferrer">Vercel</a> 維護。可部署到任何支持 <code>Node.js</code> 或 <code>Docker</code> 容器的託管平台、你自己的服務器，或使用無需服務器的「<a href="https://nextjs.org/docs/app/building-your-application/deploying/static-exports" target="_blank" rel="noreferrer">靜態導出</a>」。</p></li></ul></li><li><h3 id="react-router-v7" tabindex="-1">React Router（v7） <a class="header-anchor" href="#react-router-v7" aria-label="Permalink to &quot;React Router（v7）&quot;">​</a></h3><ul><li><h4 id="定義-1" tabindex="-1">定義 <a class="header-anchor" href="#定義-1" aria-label="Permalink to &quot;定義&quot;">​</a></h4><p><a href="https://reactrouter.com/start/framework/installation" target="_blank" rel="noreferrer">React Router</a> 是 <code>React</code> 最流行的路由庫，可以與 <code>Vite</code> 結合創建一個全端 <code>React</code> 框架。它強調標準的 <code>Web API</code> 並提供了多個適用於各種 <code>JavaScript</code> 運行時和平台的「<a href="https://github.com/remix-run/react-router-templates" target="_blank" rel="noreferrer">可部署的模板</a>」。</p></li><li><h4 id="初始化命令-1" tabindex="-1">初始化命令 <a class="header-anchor" href="#初始化命令-1" aria-label="Permalink to &quot;初始化命令&quot;">​</a></h4><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-react-router@latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h4 id="維護者" tabindex="-1">維護者 <a class="header-anchor" href="#維護者" aria-label="Permalink to &quot;維護者&quot;">​</a></h4><p>由 <a href="https://www.shopify.com/" target="_blank" rel="noreferrer">Shopify</a> 維護。</p></li></ul></li><li><h3 id="expo-for-native-apps" tabindex="-1">Expo（for native apps） <a class="header-anchor" href="#expo-for-native-apps" aria-label="Permalink to &quot;Expo（for native apps）&quot;">​</a></h3><ul><li><h4 id="定義-2" tabindex="-1">定義 <a class="header-anchor" href="#定義-2" aria-label="Permalink to &quot;定義&quot;">​</a></h4><p><a href="https://expo.dev/" target="_blank" rel="noreferrer">Expo</a> 是一個 <code>React</code> 框架，讓你可以創建支持真正原生 <code>UI</code> 的通用 <code>Android</code>、<code>iOS</code> 和 <code>Web</code> 應用。它為 <a href="https://reactnative.dev/" target="_blank" rel="noreferrer">React Native</a> 提供了一個 <code>SDK</code>，讓原生部分更易於使用。</p></li><li><h4 id="初始化命令-2" tabindex="-1">初始化命令 <a class="header-anchor" href="#初始化命令-2" aria-label="Permalink to &quot;初始化命令&quot;">​</a></h4><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-expo-app@latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h4 id="維護與費用" tabindex="-1">維護與費用 <a class="header-anchor" href="#維護與費用" aria-label="Permalink to &quot;維護與費用&quot;">​</a></h4><p>由 <code>Expo</code> 公司維護。使用 <code>Expo</code> 構建應用是免費的，可以無限制地提交到 <code>Google</code> 和 <code>Apple</code> 商店，同時 <code>Expo</code> 還提供可選的付費雲服務。<a href="https://docs.expo.dev/tutorial/introduction/" target="_blank" rel="noreferrer">Expo 教學</a></p></li></ul></li></ul><h2 id="其他框架" tabindex="-1">其他框架 <a class="header-anchor" href="#其他框架" aria-label="Permalink to &quot;其他框架&quot;">​</a></h2><p>還有一些新興的框架正在努力實現全端 <code>React</code> 願景：</p><ul><li><h4 id="tanstack-start-beta" tabindex="-1"><a href="https://tanstack.com/start/" target="_blank" rel="noreferrer">TanStack Start (Beta)</a> <a class="header-anchor" href="#tanstack-start-beta" aria-label="Permalink to &quot;[TanStack Start (Beta)](https://tanstack.com/start/)&quot;">​</a></h4><p>由 <code>TanStack Router</code> 驅動的全端 <code>React</code> 框架。使用 <code>Nitro</code> 和 <code>Vite</code> 等工具提供完整的文檔服務端渲染、流式傳輸、服務器函數、打包等功能。</p></li><li><h4 id="redwoodsdk" tabindex="-1"><a href="https://rwsdk.com/" target="_blank" rel="noreferrer">RedwoodSDK</a> <a class="header-anchor" href="#redwoodsdk" aria-label="Permalink to &quot;[RedwoodSDK](https://rwsdk.com/)&quot;">​</a></h4><p>一個全端 <code>React</code> 框架，帶有許多預裝的包和配置，方便構建全端 <code>Web</code> 應用。</p></li></ul><div class="info custom-block"><p class="custom-block-title">哪些特性構成了React 團隊的全端架構願景？</p><ul><li><p><code>Next.js</code> 的 <code>App Router</code> 打包器完全實現了官方的 <a href="https://github.com/reactjs/rfcs/blob/main/text/0188-server-components.md" target="_blank" rel="noreferrer">React Server Components 規範</a>。這讓你可以在同一個 <code>React</code> 樹中混合使用構建時、僅服務器端和交互式組件。</p></li><li><p>例如，你可以編寫一個僅在服務器端運行（或在構建期間運行）的服務器端 <code>React</code> 組件，作為 <code>async</code> 函數直接從數據庫中讀取數據（無需 <code>API</code> 端點），並添加不增大瀏覽器 <code>JavaScript bundle</code> 的渲染邏輯，然後將數據傳遞給在瀏覽器運行的交互式組件。</p></li><li><p>同時，<code>Next.js</code> 的 <code>App Router</code> 還集成了使用 <a href="https://zh-hans.react.dev/blog/2022/03/29/react-v18#suspense-in-data-frameworks" target="_blank" rel="noreferrer">Suspense</a> 的數據獲取，讓你可以直接在 <code>React</code> 樹中為 <code>UI</code> 的不同部分指定加載狀態（如 <code>&lt;Suspense fallback={&lt;TalksLoading /&gt;}&gt;</code>）。這些是 <code>React</code> 的特性而非 <code>Next.js</code> 獨有，但需要框架層面的實現，目前 <code>Next.js App Router</code> 的實現最完整。</p></li></ul></div><h2 id="從零開始" tabindex="-1">從零開始 <a class="header-anchor" href="#從零開始" aria-label="Permalink to &quot;從零開始&quot;">​</a></h2><ul><li><h4 id="適用場景" tabindex="-1">適用場景 <a class="header-anchor" href="#適用場景" aria-label="Permalink to &quot;適用場景&quot;">​</a></h4><p>如果你的應用存在現有框架無法很好滿足的限制，你希望構建自己的框架，或者你只是想學習 <code>React</code> 應用 的基礎知識，可以選擇從零開始啟動項目。</p></li><li><h4 id="特點" tabindex="-1">特點 <a class="header-anchor" href="#特點" aria-label="Permalink to &quot;特點&quot;">​</a></h4><p>給你更多的靈活性，但同時也要求你必須自己選擇用於路由、數據獲取以及其他常見使用模式的工具。</p></li><li><h4 id="構建工具" tabindex="-1">構建工具 <a class="header-anchor" href="#構建工具" aria-label="Permalink to &quot;構建工具&quot;">​</a></h4><p>可參閱「<a href="/vitepress-study/pages/f2e/docReact/reactDev/02/reactDev_02_02.html">從零構建一個 React 應用</a>」指南，引導如何使用 <a href="https://vite.dev/" target="_blank" rel="noreferrer">Vite</a>、<a href="https://parceljs.org/" target="_blank" rel="noreferrer">Parcel</a> 或 <a href="https://rsbuild.dev/" target="_blank" rel="noreferrer">RSbuild</a> 等構建工具設置新的 <code>React</code> 項目。</p></li></ul>',12)])])}const b=a(c,[["render",l]]);export{u as __pageData,b as default};
